var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"NURSE_EXTRA_NULL_NULL","text":{"KOREA":"휴우, 정말 힘이 세더군요.","JPN":"ふう、本当に力が強いんですね。","ENG":"Whew, she was really strong.","TWN":"呼，力氣還真不小呢。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"NURSE_EXTRA_NULL_NULL","text":{"KOREA":"구속복을 입히는 것만으론 모자라 밧줄을 감아둬야 할 정도라니.","JPN":"拘束衣を着せたうえに、ロープで縛り付けるなんて。","ENG":"We had to tie her up with ropes because a straitjacket was not enough.","TWN":"只穿拘束服不夠，竟然還得用繩子把他綁起來。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"침식후유증에 대해서는 꽤 알고 있다고 생각했는데, 나도 저런 환자는 처음이었다네......","JPN":"侵食後遺症に関しては精通しているほうだと思っていたが、あんな患者は私も初めてだ……","ENG":"I thought I knew everything about about Corruption trauma, but I've never seen a patient like this.","TWN":"雖然我自認為對侵蝕後遺症很有瞭解，但這種患者還真是第一次……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"NURSE_EXTRA_NULL_NULL","text":{"KOREA":"그 사람은 대체 무슨 진단명으로 불러야 할까요?","JPN":"あの患者の診断名は……？","ENG":"What should we diagnose her with?","TWN":"這個人患的病名到底叫什麼？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"글쎄. 하루 종일 침식체를 부르짖고, 환청까지 들린다는 걸 보면 불안장애의 일종 같긴 해.","JPN":"さあ。一日中、侵食体を連呼しているうえに幻聴まで聞こえてるようだから、一種の不安障害だろう。","ENG":"I'm not sure. Seeing how she's crying out for C.O. and having auditory hallucinations, it could be some sort of an anxiety disorder.","TWN":"這不好說，從他整天喊著侵蝕體，還有幻聽的樣子來看，應該是屬於焦慮症中的一種。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"NURSE_EXTRA_NULL_NULL","text":{"KOREA":"불안장애라니......","JPN":"不安障害ですか……","ENG":"An anxiety disorder...","TWN":"焦慮症……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"NURSE_EXTRA_NULL_NULL","text":{"KOREA":"그 발버둥치던 모습을 돌이켜보면 그건 너무 얌전한 표현 같은데 말이죠.","JPN":"それにしては、尋常じゃないほど暴れてました。","ENG":"That would be an understatement based on the way she was struggling.","TWN":"現在回想起他掙扎的樣子，那也算是夠安分的表現了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"NURSE_EXTRA_NULL_NULL","text":{"KOREA":"해리성 정체감 장애에, 침식체 공포증...... 같은 게 아닐까요?","JPN":"解離性同一障害と侵食体恐怖症……、ではないでしょうか？","ENG":"How about a dissociative identity disorder, on top of a C.O. phobia? What do you think?","TWN":"會不會是多重人格障礙加上侵蝕體恐懼症……？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"아니지. 그 환자가 두려워하는 건 머릿속에서 들린다는 목소리야.","JPN":"いや。あの患者は、頭の中から聞こえてくる声に怯えてる。","ENG":"No. The patient is afraid of the voices she's hearing in her head.","TWN":"不，那個患者害怕的是腦中聽到的聲音。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"침식체는 어디까지나 두려워하는 게 아닌 증오의 대상이고.","JPN":"侵食体はあくまでも、恐怖の対象ではなく憎悪の対象だ。","ENG":"She's not afraid of C.O., they are rather an object of hate.","TWN":"侵蝕體不是他恐懼，而是他憎惡的對象。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"NURSE_EXTRA_NULL_NULL","text":{"KOREA":"환자는 그 목소리를, 무슨 이름으로 부르던 것 같던데요.","JPN":"患者はその声を、確か名前で呼んでいました。","ENG":"The patient seemed to be calling that voice by a certain name.","TWN":"患者好像稱那個聲音叫……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"그래, 오르카...... 라고 하더군.","JPN":"ああ、オルカ……、と呼んでいた。","ENG":"Yes, Orca... is what she said.","TWN":"對，奧爾卡……他是這麼說的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"NURSE_EXTRA_NULL_NULL","text":{"KOREA":"......범고래요? 바다에 사는?","JPN":"……シャチですか？あの、海の？","ENG":"The killer whale? That lives in the ocean?","TWN":"……是虎鯨嗎？在海裡的那個？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"뭐, 그렇게 읽을 수도 있겠지.","JPN":"ああ、そうとも言えるな。","ENG":"Well, I suppose you could call it that.","TWN":"這個嘛，是也可以這樣念啦。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"하지만 야전 의무병 시절에 내가 들었던 오르카란건......","JPN":"だが野戦衛生兵だった頃、私が聞いたオルカというのは……","ENG":"But what I heard while working out in the fields as a medic...","TWN":"但是我在野戰醫療兵時期，聽到的奧爾卡是……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>선생님! 302호실 중환자가 도망쳤습니다!</color>","JPN":"<color=#ffd34c>先生！302号室の患者が脱走しました！</color>","ENG":"<color=#ffd34c>Doctor! The critical patient from room 302 escaped!</color>","TWN":"<color=#ffd34c>醫生，302室的重症患者逃跑了！</color>"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L18_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"......뭐라고! 하지만 어떻게?","JPN":"……何だと？しかし、どうやって？","ENG":"What?! But how?","TWN":"……你說什麼！可是這怎麼可能？！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>부, 분명 아무 것도 없었는데, 갑자기 침식체가 나타났다더니 손에서 칼이 튀어나와선......</color>","JPN":"<color=#ffd34c>た、確かに何も持っていなかったのに、急に侵食体が現れたといって手からナイフを……</color>","ENG":"<color=#ffd34c>Th-there was nothing there, but she suddenly shouted that a C.O. had appeared, and pulled out a knife...</color>","TWN":"<color=#ffd34c>本、本來一切都很好，但侵蝕體突然出現後，患者的手上就出現了刀……</color>"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L20_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"칼이라고?! 누구 다친 사람 있나?","JPN":"ナイフだと！ケガ人は！？","ENG":"A knife?! Is anyone hurt?","TWN":"刀？！有人受傷了嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GUARD_EXTRA_NULL_NULL","text":{"KOREA":"아, 아뇨! 환자는 그대로 창문으로 뛰어내렸습니다.","JPN":"い、いません！患者はそのまま、窓から飛び降りました。","ENG":"N-no! The patient immediately jumped out of the window.","TWN":"沒、沒有人受傷！但患者就直接從窗戶跳出去了！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GUARD_EXTRA_NULL_NULL","text":{"KOREA":"그러곤 아무렇지 않게 담장까지 한달음에 뛰어넘었어요.","JPN":"そして、軽々と塀を飛び越えていきました。","ENG":"And then she jumped over the wall like it was nothing.","TWN":"然後隨便一跳就跳過了圍牆。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GUARD_EXTRA_NULL_NULL","text":{"KOREA":"지금 저희가 뒤를 쫓고 있습니다만 너무 빨라서......","JPN":"今、後を追っていますが早すぎて……","ENG":"We're chasing after her right now, but she's too fast...","TWN":"雖然我們現在正在追他，但他跑得實在太快了……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GUARD_EXTRA_NULL_NULL","text":{"KOREA":"자, 잠깐. 저거. 침식체 아닌가?","JPN":"あ、あれ、侵食体じゃないか？","ENG":"W-wait. Look over there. Isn't that a C.O.?","TWN":"等、等一下。那不是侵蝕體嗎？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GUARD_EXTRA_NULL_NULL","text":{"KOREA":"어이! 멈춰! 위험해! 물러서라고!","JPN":"おい！止まれ！危険だ！こっちへ来い！","ENG":"Hey! Stop! It's dangerous! Step back!","TWN":"喂！停下來！危險啊！快退後！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>이보게! 이게 무슨 소린가?!</color>","JPN":"<color=#ffd34c>どうした！何が起きてる！？</color>","ENG":"<color=#ffd34c>Hey! What is that sound?!</color>","TWN":"<color=#ffd34c>喂！這是什麼聲音啊？！</color>"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L31_1","type":"dialog","speaker":"GUARD_EXTRA_NULL_NULL","text":{"KOREA":"환자가...... 침식체들과 싸움을......","JPN":"患者が……、侵食体と戦って……","ENG":"The patient... is fighting the C.O....","TWN":"患者……正在和侵蝕體戰鬥……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_DAGGER_STING_SMALL_03"},{"id":"L32_1","type":"dialog","speaker":"GUARD_EXTRA_NULL_NULL","text":{"KOREA":"아니, 일방적으로 침식체를 사냥하고 있습니다.","JPN":"いや、侵食体を相手に一方的な狩りをしています。","ENG":"I mean, she's massacring the C.O.","TWN":"不，他是單方面地在獵殺侵蝕體。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_24"},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>침식체라고?</color>","JPN":"<color=#ffd34c>侵食体だと？</color>","ENG":"<color=#ffd34c>C.O.?</color>","TWN":"<color=#ffd34c>獵殺侵蝕體？</color>"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L35_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>......그쪽은 맡겨두고 돌아와! 우선 병원의 환자들부터 대피시키지!</color>","JPN":"<color=#ffd34c>……そのまま任せて戻ってこい！まず患者を避難させるぞ！</color>","ENG":"<color=#ffd34c>Leave those to her and come back! We have to get the other patients out of the hospital!</color>","TWN":"<color=#ffd34c>……那邊就交給他，你們快回來！先讓醫院裡的患者去避難！</color>"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L36_1","type":"dialog","speaker":"GUARD_EXTRA_NULL_NULL","text":{"KOREA":"마, 맡겨두라니 그게 무슨 말씀인가요?","JPN":"ま、任せるってどういうことですか？","ENG":"W-what do you mean leave them to her?","TWN":"居、居然說要交給他……你在說什麼？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"GUARD_EXTRA_NULL_NULL","text":{"KOREA":"군인도 아니고, 칼자루 쥔 환자에게 말입니까?","JPN":"軍人でもない、ナイフを持った患者ですよ？","ENG":"She's just a patient with a knife, not a soldier!","TWN":"他不是軍人，而是只拿著一把小刀的患者啊？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>그 사람은 괜찮을 테니 서둘러! 병원 안에 있는 환자들이 우선일세!</color>","JPN":"<color=#ffd34c>その患者なら任せても平気だ！今は病院の患者が先だ！</color>","ENG":"<color=#ffd34c>She'll be fine. Hurry! We have to take care of the patients in the hospital first!</color>","TWN":"<color=#ffd34c>那個人不會有事的，快點！醫院裡的患者優先！</color>"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L40_1","type":"dialog","speaker":"GUARD_EXTRA_NULL_NULL","text":{"KOREA":"아, 알겠습니다!","JPN":"わ、わかりました！","ENG":"R-roger that!","TWN":"知、知道了！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_DUMMY","text":{"KOREA":"......마지막 행적까지 참 화려하군요.","JPN":"……最後まで派手ですね。","ENG":"She left quite the trail up to the last appearance.","TWN":"……就連最後的行跡都這麼華麗呢。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L44_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_DUMMY","text":{"KOREA":"정말로 이런 통제도 안 되는 맹수를 기용하실 생각인가요?","JPN":"本当にこのコントロールが利かない猛獣を採用するつもりですか？","ENG":"Are you really going to hire this uncontrollable beast?","TWN":"您真的要聘用這種無法控制的猛獸嗎？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_DUMMY","text":{"KOREA":"훌륭한 재원이 될 수도 있는데, 저대로 야생에 방치해두기엔 너무 아깝지 않나.","JPN":"優秀な人材になり得るのに、野生に放置するのはもったいないだろ？","ENG":"She could become a fine member of our company. It would be a waste to just leave her out in the wild.","TWN":"他能成為優秀的財源，就這樣野放在外面，未免也太可惜了吧。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_DUMMY","text":{"KOREA":"......‘상속자’에 관해선 개인적인 호기심도 있고 말이지.","JPN":"……「相続者」に関しては、個人的に興味もあるしな。","ENG":"And I have some personal curiosity regarding the Successor.","TWN":"……然後關於''繼承者''，也有我個人的好奇心在裡面。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_DUMMY","text":{"KOREA":"휴, 알겠습니다. 조사를 좀 더 진행해서 현 소유자를 찾아보도록 하죠.","JPN":"はあ、わかりました。もう少し調査を進めて、現在の所有者を探し出します。","ENG":"*Sigh* Fine. I'll do some more research to find the current owner.","TWN":"呼，知道了。我會再進一步調查，找出現在的所有者。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_DUMMY","text":{"KOREA":"찾아낸다고 한들... 저희 말을 들어주기나 할지조차 미지수지만요.","JPN":"見つけたとしても……、話を聞いてくれるとは思えませんが。","ENG":"Although I'm not sure... if we'll be able to talk to her even if we find her.","TWN":"但就算找到了……他會不會聽我們的話，都還是個未知數呢。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};